"use strict";(globalThis.webpackChunksite=globalThis.webpackChunksite||[]).push([[1593],{23998(e,t,a){a.r(t),a.d(t,{assets:()=>l,contentTitle:()=>s,default:()=>u,frontMatter:()=>r,metadata:()=>n,toc:()=>c});const n=JSON.parse('{"id":"reference/cli-reference/stave-capabilities-catalog","title":"stave capabilities catalog","description":"Print the user-facing capability catalog","source":"@site/../stave-guide/reference/cli-reference/stave-capabilities-catalog.md","sourceDirName":"reference/cli-reference","slug":"/reference/cli-reference/stave-capabilities-catalog","permalink":"/docs/reference/cli-reference/stave-capabilities-catalog","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":66,"frontMatter":{"title":"stave capabilities catalog","sidebar_label":"capabilities catalog","sidebar_position":66,"description":"Print the user-facing capability catalog"},"sidebar":"docs","previous":{"title":"bundle audit","permalink":"/docs/reference/cli-reference/stave-bundle-audit"},"next":{"title":"cel eval","permalink":"/docs/reference/cli-reference/stave-cel-eval"}}');var i=a(74848),o=a(28453);const r={title:"stave capabilities catalog",sidebar_label:"capabilities catalog",sidebar_position:66,description:"Print the user-facing capability catalog"},s="stave capabilities catalog",l={},c=[];function d(e){const t={code:"code",h1:"h1",header:"header",pre:"pre",...(0,o.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.header,{children:(0,i.jsx)(t.h1,{id:"stave-capabilities-catalog",children:"stave capabilities catalog"})}),"\n",(0,i.jsx)(t.pre,{children:(0,i.jsx)(t.code,{className:"language-text",children:"Catalog emits the grouped view of what Stave can check: control\ngroups by (service, category), compound chains, and operational\nfeatures (readiness, gaps, drift, validate, export-sir). Pair with\n`stave search <query>` to look up by intent.\n\nUse --service to filter to one service (s3, iam, lambda, \u2026) or\n--category to filter within a service. --kind narrows to one of\ncontrol_group | chain | operational.\n\nOutput is paged through $PAGER (then 'less -R', then 'more') when stdout is a\nterminal, and written plain and unpaged when stdout is a pipe, a redirect, or\nCI \u2014 so '... | grep' and '... > file' are unaffected. JSON is never paged.\nUse --no-pager to force plain output on a terminal.\n\nDrill-down mirrors 'man <topic>':\n  catalog                 summary: one line per service\n  catalog <SERVICE>       that service's capabilities, one line each\n  catalog <SERVICE> --leaf  the leaf controls (individual control IDs)\n  catalog --severity CRITICAL  only the matching leaf controls, any level\n\n--severity matches an EXACT level and lists control-group controls only;\nchains and operational features carry no severity and are excluded (stated in\nthe output, not silently dropped). --leaf is the leaf drill-down: --controls/-i\nis already the catalog directory, so the leaf toggle is a distinct flag.\n\nInputs:\n  --service SVC    Filter to one service (e.g. s3); also accepted positionally\n  --category CAT   Filter to one category within --service (e.g. public)\n  --kind K         control_group | chain | operational\n  --severity SEV   critical | high | medium | low | info (leaf controls)\n  --leaf           Drill to individual leaf controls\n  --format F       auto (default; paged on a TTY) | text | wide | json\n  --no-pager       Never page, even on a terminal\n  --controls DIR   Control catalog directory (default: controls)\n  --chains DIR     Chain catalog directory (default: chains)\n\nExit codes:\n  0   Success\n  2   Invalid input\n  4   Internal error\n\nUsage:\n  stave capabilities catalog [flags]\n\nExamples:\n  stave capabilities catalog\n  stave capabilities catalog s3\n  stave capabilities catalog --service s3\n  stave capabilities catalog --kind chain\n  stave capabilities catalog --format json | jq '.capabilities | length'\n\nFlags:\n      --category string   filter to one category (requires --service)\n      --chains string     chain catalog directory (default \"chains\")\n  -i, --controls string   control catalog directory (default \"controls\")\n  -f, --format string     output format: auto | text | wide | json (default \"auto\")\n  -h, --help              help for catalog\n      --kind string       filter to one kind: control_group | chain | operational\n      --leaf              drill to leaf controls (the individual control IDs); pairs with a service\n      --no-pager          never page output, even on a terminal\n      --service string    filter to one service\n      --severity string   show only leaf controls of this severity: critical | high | medium | low | info\n\nGlobal Flags:\n      --allow-symlink-output   Allow writing output through symlinks (default: refuse)\n      --force                  Allow overwriting existing output files\n      --log-file string        Write logs to file (default: stderr)\n      --log-format string      Log format: text|json (default \"text\")\n      --log-level string       Log level: debug|info|warn|error (overrides -v)\n      --log-timestamps         Include timestamps in logs (breaks determinism)\n      --log-timings            Include timing information (breaks determinism)\n      --no-color               Disable ANSI colors in output\n      --path-mode string       Path rendering in errors/logs: base (basename only) or full (absolute paths) Resolved default may come from STAVE_* env vars, stave.yaml, user config, or built-in.\n      --quiet                  Suppress output (exit code only) Resolved default may come from STAVE_* env vars, stave.yaml, user config, or built-in.\n      --require-offline        Assert offline operation: fail if proxy env vars (HTTP_PROXY, HTTPS_PROXY, ALL_PROXY) are set\n      --sanitize               Sanitize infrastructure identifiers (bucket names, ARNs, policies) from output Resolved default may come from STAVE_* env vars, stave.yaml, user config, or built-in.\n      --strict                 Enable strict integrity checks for embedded registries and references\n  -v, --verbose count          Increase verbosity (-v=INFO, -vv=DEBUG)\n  -y, --yes                    Auto-confirm all interactive prompts (distinct from --force which controls file overwriting)\n"})})]})}function u(e={}){const{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(d,{...e})}):d(e)}},28453(e,t,a){a.d(t,{R:()=>r,x:()=>s});var n=a(96540);const i={},o=n.createContext(i);function r(e){const t=n.useContext(o);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function s(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:r(e.components),n.createElement(o.Provider,{value:t},e.children)}}}]);